function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: Map<number, [number, number][]> = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u)!.push([v, cost]);
    }

    // Use a max-heap to keep track of the maximum minimum edge cost
    // Since JavaScript's priority queue is a min-heap, we'll store negative values
    const maxHeap: [number, number, number][] = [[0, 0, 0]]; // [min_edge_cost, current_node, current_total_cost]
    const visited: boolean[] = new Array(n).fill(false);
    visited[0] = true;

    while (maxHeap.length > 0) {
        const [minEdge, node, totalCost] = maxHeap.pop() as [number, number, number];
        const currentMinEdge = -minEdge; // Convert back to positive for comparison

        if (node === n - 1) {
            return currentMinEdge;
        }

        if (!graph.has(node)) continue;

        for (const [neighbor, cost] of graph.get(node)!) {
            if (!online[neighbor] || visited[neighbor]) continue;

            const newTotal = totalCost + cost;
            if (newTotal <= k) {
                const newMinEdge = Math.min(currentMinEdge, cost);
                maxHeap.push([-newMinEdge, neighbor, newTotal]);
                visited[neighbor] = true;
            }
        }
    }

    return -1;
}
